  socket.once("data", resolve)
  socket.once("error", reject)
})

good:
Effect.async<Buffer, SocketError>((resume) => {
  socket.once("data", (d) => resume(Effect.succeed(d)))
  socket.once("error", (e) => resume(Effect.fail(new SocketError({ cause: e }))))
})

